import { addCommonRoleOptions, commonRoleOptions } from './utils.js';
export const deleteRole = {
    name: 'delete',
    alias: ['del', 'strike'],
    options: { ...commonRoleOptions('delete') },
    body: {
        type: 'myst',
        required: true,
    },
    run(data) {
        const del = { type: 'delete', children: data.body };
        addCommonRoleOptions(data, del);
        return [del];
    },
};
